patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..7508aa820096 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3130,6 +3130,20 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
         replaceOperand(SI, 1, TrueSI->getTrueValue());
         return &SI;
       }
+      // Fold select (select X, true, Y), (select X, A, B), C
+      // into select X, A, (select Y, B, C)
+      // If X is false: outer condition is Y, and (select X, A, B) = B
+      //   so result is (select Y, B, C)
+      // If X is true: outer condition is true, so result is (select X, A, B) = A
+      SelectInst *CondSI = dyn_cast<SelectInst>(CondVal);
+      if (CondSI && CondSI->hasOneUse() &&
+          CondSI->getCondition() == TrueSI->getCondition() &&
+          match(CondSI->getTrueValue(), m_One())) {
+        Value *NewFalseVal = Builder.CreateSelect(
+            CondSI->getFalseValue(), TrueSI->getFalseValue(), FalseVal);
+        return SelectInst::Create(CondSI->getCondition(), TrueSI->getTrueValue(),
+                                  NewFalseVal);
+      }
     }
   }
   if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {

